code = """import json
import re
import pandas as pd
from collections import Counter, defaultdict

# Read the data
with open(locals()['var_functions.query_db:20'], 'r') as f:
    clinical_data = json.load(f)

with open(locals()['var_functions.query_db:18'], 'r') as f:
    cdh1_mutations = json.load(f)

# Extract patient barcodes from clinical data (alive BRCA patients)
alive_brca_patients = []
for record in clinical_data:
    # Extract TCGA barcode from Patient_description
    desc = record['Patient_description']
    # Look for TCGA-XX-XXXX pattern
    match = re.search(r'(TCGA-\w{2}-\w{4})', desc)
    if match:
        barcode = match.group(1)
        alive_brca_patients.append({
            'barcode': barcode,
            'histological_type': record['histological_type']
        })

# Get set of CDH1 mutated patient barcodes
cdh1_barcodes = set([mut['ParticipantBarcode'] for mut in cdh1_mutations])

print('__RESULT__:')
print(json.dumps({
    'total_alive_brca': len(alive_brca_patients),
    'total_cdh1_mutations': len(cdh1_barcodes),
    'sample_alive_brca': alive_brca_patients[:5],
    'sample_cdh1_barcode': list(cdh1_barcodes)[:5]
}))"""

